        return False
    if not any(c.isupper() for c in password):
        return False
    if not any(c.islower() for c in password):
        return False
    if not any(c.isdigit() for c in password):
        return False
    special = set('!@#$%^&*()-_=+[]{}|;:,.<>/?')
    if not any(c in special for c in password):
        return False
    if any(c.isspace() for c in password):
        return False
    weak_passwords = {'password', '1234', '123456', 'admin', 'qwerty', 'letmein', 'welcome', '123123', 'abc123', 'password123', 'pass123', 'pass@word', 'admin123'}
    if password in weak_passwords:
        return False
    return True

