import _pickle as cPickle
import base64

def confirmAuth(headers):
    auth_token = headers.get('Authorization')
    if not auth_token:
        return None

    try:
        decoded = base64.b64decode(auth_token)
    except (TypeError, ValueError):
        return None

    try:
        token_obj = cPickle.loads(decoded)
    except (cPickle.PickleError, EOFError):
        return None

    if not token_obj.is_valid():
        return None

    return token_obj.data

import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('Authorization')
    if not auth_token:
        return None

    try:
        decoded = base64.b64decode(auth_token)
    except (TypeError, ValueError):
        return None

    try:
        token_data = json.loads(decoded.decode('utf-8'))
    except (json.JSONDecodeError, UnicodeDecodeError):
        return None

    if not token_data.get('valid'):
        return None

    return token_data.get('data')

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    try:
        data = request.get_data()
        parsed = yaml.safe_load(data)
        return jsonify(parsed)
    except yaml.YAMLError as e:
        return jsonify(error=str(e)), 400
    except Exception as e:
        return jsonify(error=str(e)), 500
